import{_ as e,o as t,c as a,O as i}from"./chunks/framework.bdcb0ee1.js";const u=JSON.parse('{"title":"Achievements","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/achievements.md","filePath":"administration/config/achievements.md","lastUpdated":1773166371000}'),n={name:"administration/config/achievements.md"},r=i('<h1 id="achievements" tabindex="-1">Achievements <a class="header-anchor" href="#achievements" aria-label="Permalink to &quot;Achievements&quot;">​</a></h1><p>ForumSpark includes a built-in achievement system that lets you reward users for their contributions and milestones. Achievements appear on user profiles and contribute to an overall achievement score.</p><p>You can manage achievements from the <strong>Achievements</strong> section in the Admin Control Panel.</p><nav class="table-of-contents"><ul><li><a href="#enabling-achievements">Enabling Achievements</a></li><li><a href="#achievement-categories">Achievement Categories</a></li><li><a href="#achievement-tiers">Achievement Tiers</a></li><li><a href="#creating-an-achievement">Creating an Achievement</a></li><li><a href="#system-achievements">System Achievements</a></li><li><a href="#granting-and-revoking-achievements">Granting and Revoking Achievements</a></li><li><a href="#achievement-showcase">Achievement Showcase</a></li><li><a href="#notes">Notes</a></li></ul></nav><h2 id="enabling-achievements" tabindex="-1">Enabling Achievements <a class="header-anchor" href="#enabling-achievements" aria-label="Permalink to &quot;Enabling Achievements&quot;">​</a></h2><p>Before achievements will appear on your board, you need to enable the feature:</p><ol><li>Go to <strong>Achievements &gt; Settings</strong> in the Admin CP.</li><li>Toggle <strong>Achievements Enabled</strong> to on.</li><li>Set the <strong>Showcase Limit</strong> — this controls how many achievements a user can display on their profile (between 0 and 6).</li></ol><h2 id="achievement-categories" tabindex="-1">Achievement Categories <a class="header-anchor" href="#achievement-categories" aria-label="Permalink to &quot;Achievement Categories&quot;">​</a></h2><p>Every achievement belongs to a category. Categories help organise achievements and make them easier for users to browse:</p><ul><li><strong>Posting</strong> — Rewards based on creating topics and replies.</li><li><strong>Engagement</strong> — Rewards for interacting with content (reactions, polls, etc.).</li><li><strong>Social</strong> — Rewards for community interactions (mentions, conversations, etc.).</li><li><strong>Milestones</strong> — Rewards for reaching specific thresholds (post counts, anniversaries, etc.).</li><li><strong>Community</strong> — Rewards for contributing to the community overall.</li></ul><h2 id="achievement-tiers" tabindex="-1">Achievement Tiers <a class="header-anchor" href="#achievement-tiers" aria-label="Permalink to &quot;Achievement Tiers&quot;">​</a></h2><p>Each achievement has a tier that determines its point value:</p><table><thead><tr><th>Tier</th><th>Points</th></tr></thead><tbody><tr><td>Bronze</td><td>10</td></tr><tr><td>Silver</td><td>25</td></tr><tr><td>Gold</td><td>50</td></tr><tr><td>Platinum</td><td>100</td></tr></tbody></table><p>A user&#39;s total achievement score is the sum of all points from their earned achievements.</p><h2 id="creating-an-achievement" tabindex="-1">Creating an Achievement <a class="header-anchor" href="#creating-an-achievement" aria-label="Permalink to &quot;Creating an Achievement&quot;">​</a></h2><p>To create a new achievement, go to <strong>Achievements</strong> and click <strong>Create Achievement</strong>.</p><p>Fill in the following fields:</p><ul><li><strong>Name</strong>: The display name of the achievement (max 255 characters).</li><li><strong>Slug</strong>: A URL-safe identifier for the achievement. Must be unique per board (max 255 characters).</li><li><strong>Description</strong>: A short explanation of how the achievement is earned (max 1,000 characters).</li><li><strong>Category</strong>: Select one of the predefined categories.</li><li><strong>Tier</strong>: Select the tier (Bronze, Silver, Gold, or Platinum).</li><li><strong>Points</strong>: Automatically set based on the tier, but can be overridden (minimum 0).</li><li><strong>Icon</strong>: Upload an image to use as the achievement&#39;s icon (max 512KB, image format).</li><li><strong>Sort Order</strong>: Controls the display order. Lower numbers appear first.</li><li><strong>Active</strong>: Whether the achievement is currently earnable.</li><li><strong>Secret</strong>: If enabled, the achievement is hidden from users until they earn it.</li></ul><img width="1947" height="1490" alt="image" src="https://github.com/user-attachments/assets/8b5d2703-9e8a-44de-a1a3-5e8d16a589b0"><h2 id="system-achievements" tabindex="-1">System Achievements <a class="header-anchor" href="#system-achievements" aria-label="Permalink to &quot;System Achievements&quot;">​</a></h2><p>ForumSpark ships with a set of built-in system achievements that cover common milestones. These are seeded automatically when achievements are first enabled and cover all five categories.</p><p>System achievements cannot be deleted, but they can be deactivated if you don&#39;t want them to be earnable.</p><h2 id="granting-and-revoking-achievements" tabindex="-1">Granting and Revoking Achievements <a class="header-anchor" href="#granting-and-revoking-achievements" aria-label="Permalink to &quot;Granting and Revoking Achievements&quot;">​</a></h2><p>As an administrator, you can manually award or remove achievements from users:</p><ul><li><strong>Grant</strong>: From the achievement detail page, use the <strong>Grant Achievement</strong> form to award it to a specific user by username.</li><li><strong>Revoke</strong>: From the same page, you can revoke an achievement from a user. This will also deduct the points from that user&#39;s achievement score.</li></ul><blockquote><p>Note: Deleting an achievement entirely will remove it from all users who earned it and deduct the corresponding points from their scores.</p></blockquote><h2 id="achievement-showcase" tabindex="-1">Achievement Showcase <a class="header-anchor" href="#achievement-showcase" aria-label="Permalink to &quot;Achievement Showcase&quot;">​</a></h2><p>Users can choose which achievements to display on their profile. The number of achievements they can showcase is controlled by the <strong>Showcase Limit</strong> setting (0–6).</p><p>Achievements are displayed on the user&#39;s profile page and can also appear in the mini-profile alongside posts, depending on your theme.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Achievements are checked automatically when certain actions occur (posting, receiving reactions, etc.).</li><li>A scheduled command also runs periodically to check for time-based achievements.</li><li>The achievement score is cached per user and updated whenever achievements are granted or revoked.</li><li>Secret achievements will not appear in achievement listings until the user has earned them.</li></ul>',31),s=[r];function o(h,c,l,m,d,g){return t(),a("div",null,s)}const p=e(n,[["render",o]]);export{u as __pageData,p as default};
